(()=>{'use strict';
const $=s=>document.querySelector(s),T=v=>String(v??'').trim();let ov,body;
function cleanPs(v){const p=T(v).split(/\s+/).filter(Boolean);if(p.length===2&&p[0]===p[1])return p[0];const out=[];p.forEach(x=>{if(!out.includes(x))out.push(x)});return out.join(' ')}
function css(){if($('#psPickerModal286Css'))return;const st=document.createElement('style');st.id='psPickerModal286Css';st.textContent=`.psPickBtn286{width:100%;height:42px;border:1px solid #087b34;background:#f0fdf4;color:#065f46;border-radius:9px;font-weight:950;text-align:left;padding:0 12px}.psOverlay286{position:fixed;inset:0;background:rgba(15,23,42,.55);z-index:171;display:none;align-items:center;justify-content:center;padding:18px}.psOverlay286.on{display:flex}.psSheet286{width:min(92vw,680px);max-height:86vh;background:#fff;border-radius:18px;box-shadow:0 22px 80px #0006;display:flex;flex-direction:column;overflow:hidden}.psHead286{background:#087b34;color:#fff;padding:14px 16px;display:flex;justify-content:space-between;align-items:center;gap:8px;font-size:17px}.psClose286{height:34px;border:1px solid #ffffff66;background:#0001;color:#fff;border-radius:8px;font-weight:900;padding:0 12px}.psSearch286{padding:12px;border-bottom:1px solid #e5e7eb}.psSearch286 input{width:100%;height:44px;border:1px solid #cbd5e1;border-radius:10px;padding:0 12px;font-weight:900;font-size:15px}.psBody286{padding:12px;overflow:auto}.psGrid286{display:grid;grid-template-columns:repeat(2,1fr);gap:9px}.psItem286{border:1px solid #d1d5db;background:#fff;border-radius:10px;padding:12px 10px;font-weight:950;text-align:left;font-size:15px}.psItem286.on{border-color:#087b34;background:#ecfdf5;color:#065f27}.psFoot286{padding:12px;border-top:1px solid #e5e7eb;display:grid;grid-template-columns:1fr 1fr;gap:10px}.psFoot286 button{height:46px;border-radius:10px;font-weight:950;font-size:15px}.psClear286{border:1px solid #d1d5db;background:#fff;color:#4b5563}.psOk286{border:0;background:#087b34;color:#fff}@media(max-width:520px){.psOverlay286{padding:10px}.psSheet286{width:96vw;max-height:88vh}.psGrid286{grid-template-columns:1fr}.psHead286{font-size:16px}}`;document.head.appendChild(st)}
function options(){const el=$('#psSelect');if(!el)return[];return[...el.options].map(o=>cleanPs(o.value||o.textContent)).filter(Boolean).filter((x,i,a)=>a.indexOf(x)===i).sort((a,b)=>a.localeCompare(b,'th'))}
function ensure(){css();if(ov)return;ov=document.createElement('div');ov.className='psOverlay286';ov.innerHTML='<div class="psSheet286"><div class="psHead286"><b>аєАаЄ•аЄЈаЄ≠аЄБ PS</b><button class="psClose286">аЄЫаЄіаЄФ</button></div><div class="psSearch286"><input id="psSearch286" placeholder="аЄДаєЙаЄЩаЄЂаЄ≤ PS"></div><div class="psBody286"></div><div class="psFoot286"><button class="psClear286">аЄ•аєЙаЄ≤аЄЗ</button><button class="psOk286">аЄХаЄБаЄ•аЄЗ</button></div></div>';document.body.appendChild(ov);body=ov.querySelector('.psBody286');ov.querySelector('.psClose286').onclick=close;ov.querySelector('.psClear286').onclick=()=>selectPs('');ov.querySelector('.psOk286').onclick=close;ov.onclick=e=>{if(e.target===ov)close()};ov.querySelector('#psSearch286').oninput=render}
function current(){return cleanPs($('#psSelect')?.value||'')}
function selectPs(v){const el=$('#psSelect');if(el){el.value=v;el.dispatchEvent(new Event('change',{bubbles:true}));el.dispatchEvent(new Event('input',{bubbles:true}))}syncButton();render();if(v)close()}
function render(){ensure();const q=T($('#psSearch286')?.value).toLowerCase(),cur=current();let list=options();if(q)list=list.filter(x=>x.toLowerCase().includes(q));body.innerHTML='<div class="psGrid286">'+list.map(x=>`<button class="psItem286 ${x===cur?'on':''}" data-v="${x}">${x}</button>`).join('')+'</div>';body.querySelectorAll('.psItem286').forEach(b=>b.onclick=()=>selectPs(b.dataset.v))}
function open(){ensure();const s=$('#psSearch286');if(s)s.value='';render();ov.classList.add('on')}
function close(){ov?.classList.remove('on')}
function syncButton(){const b=$('#psPickBtn286'),v=current();if(b)b.textContent=v?`PS: ${v} вЦЉ`:'аєАаЄ•аЄЈаЄ≠аЄБ PS вЦЉ'}
function hideSelect(){const el=$('#psSelect');if(!el)return;const field=el.closest('.field');if(!field)return;if(!$('#psPickBtn286')){const b=document.createElement('button');b.type='button';b.id='psPickBtn286';b.className='psPickBtn286';b.onclick=open;field.insertBefore(b,el)}el.style.position='absolute';el.style.left='-9999px';el.style.width='1px';el.style.height='1px';el.style.opacity='0';el.style.pointerEvents='none';syncButton();if(!el.dataset.psModal286){el.dataset.psModal286='1';el.addEventListener('change',()=>{cleanOptions();syncButton()})}}
function cleanOptions(){const el=$('#psSelect');if(!el)return;[...el.options].forEach(o=>{const c=cleanPs(o.value||o.textContent);if(c){o.value=c;o.textContent=c}})}
function boot(){cleanOptions();hideSelect();let n=0;const tick=()=>{cleanOptions();hideSelect();if(++n<40)setTimeout(tick,300)};setTimeout(tick,300)}
document.addEventListener('DOMContentLoaded',boot);if(document.readyState!=='loading')boot();
})();